#include <stdio.h>

int main() {
  FILE *fp;
  fp = fopen("output.txt", "w");
  if (fp == NULL) {
    printf("Error\n");
    return 1;
  }
  fprintf(fp, "Name: %s\n", "Alice");
  fprintf(fp, "Age: %d\n", 25);
  fputs("End of record\n", fp);
  fclose(fp);
  fp = fopen("output.txt", "a");
  fprintf(fp, "Appended line\n");
  fclose(fp);
  return 0;
}
